-- {"operators": "OUTER_JOIN,AGGREGATE,FILTER,CASE", "complexity": "medium", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": true, "tables": "ORDER_LINE,STOCK", "lakeflow": "silver_rides", "note": "Lakeflow silver-rides analog: LEFT JOIN + computed column + WHERE filter + GROUP BY. Mirrors revenue-per-order enrichment with stock-level adjustment."}
SELECT ol.OL_W_ID, ol.OL_D_ID, ol.OL_O_ID, COUNT(*) AS line_count, SUM(ol.OL_AMOUNT) AS total_amount, SUM(CASE WHEN s.S_QUANTITY < 10 THEN ol.OL_AMOUNT * 1.5 ELSE ol.OL_AMOUNT END) AS adjusted_amount FROM ORDER_LINE ol LEFT JOIN STOCK s ON ol.OL_W_ID = s.S_W_ID AND ol.OL_I_ID = s.S_I_ID WHERE ol.OL_AMOUNT > 0 GROUP BY ol.OL_W_ID, ol.OL_D_ID, ol.OL_O_ID
